import { createSignal } from 'solid-js';
import type {
  ContextRecord,
  RegistryItem,
  RenderedItem,
  ContextMenuHandle,
} from './context-menu.types';

type MenuState = {
  x: number;
  y: number;
  items: RenderedItem[];
} | null;

const [menuState, setMenuState] = createSignal<MenuState>(null);

export const contextMenuStore = {
  menuState,
  close: () => setMenuState(null),
  isOpen: () => menuState() !== null,
};

export function createContextMenuHandle<
  TContext extends ContextRecord,
>(): ContextMenuHandle<TContext> {
  const registry = new Map<string, RegistryItem<TContext>>();

  function register(item: RegistryItem<TContext>): void {
    registry.set(item.key, item);
  }

  function unregister(key: string): void {
    registry.delete(key);
  }

  function buildRenderedItems(ctx: TContext): RenderedItem[] {
    const visible = [...registry.values()]
      .filter(item => !item.when || item.when(ctx))
      .sort((a, b) => (a.order ?? 100) - (b.order ?? 100));

    if (visible.length === 0) return [];

    const groups: RegistryItem<TContext>[][] = [];
    const groupMap = new Map<string, RegistryItem<TContext>[]>();

    for (const item of visible) {
      const g = item.group ?? '__default__';
      if (!groupMap.has(g)) {
        const arr: RegistryItem<TContext>[] = [];
        groupMap.set(g, arr);
        groups.push(arr);
      }
      groupMap.get(g)!.push(item);
    }

    const result: RenderedItem[] = [];
    for (let i = 0; i < groups.length; i++) {
      if (i > 0) result.push({ type: 'separator' });
      for (const item of groups[i]) {
        if (item.type === 'item') {
          result.push({
            type: 'item',
            key: item.key,
            label: item.label,
            disabled: item.disabled?.(ctx),
            shortcut: item.shortcut,
            prefixIcon: item.prefixIcon,
            onClick: () => item.onClick(ctx),
          });
        } else {
          result.push({
            type: 'submenu',
            key: item.key,
            label: item.label,
            disabled: item.disabled?.(ctx),
            shortcut: item.shortcut,
            prefixIcon: item.prefixIcon,

            items: item.items
              .filter(sub => !sub.when || sub.when(ctx))
              .map(sub => {
                if (sub.type === 'item') {
                  return {
                    type: 'item' as const,
                    key: sub.key,
                    label: sub.label,
                    disabled: sub.disabled?.(ctx),
                    shortcut: sub.shortcut,
                    prefixIcon: sub.prefixIcon,
                    onClick: () => sub.onClick(ctx),
                  };
                }
                return { type: 'separator' as const };
              }),
          });
        }
      }
    }
    return result;
  }

  function trigger(e: MouseEvent, ctx: TContext): void {
    e.preventDefault();
    e.stopPropagation();
    const items = buildRenderedItems(ctx);
    if (items.length === 0) return;
    setMenuState({ x: e.clientX, y: e.clientY, items });
  }

  return { register, unregister, trigger };
}
